let currentLang = 'uz';

function setLang(lang) {
    currentLang = lang;
    document.querySelectorAll('.lang-btn').forEach(b => b.classList.remove('active'));
    document.querySelector(`.lang-btn[onclick="setLang('${lang}')"]`).classList.add('active');
    const L = LANGS[lang];

    // Guest names per language
    const guestNames = {
        uz: {
            "1":"Hotinjon","2":"Zuhriddin","3":"Obbbooosss","4":"Qori ota",
            "5":"Otabek","6":"Aslbek","7":"Sherzod","8":"Sardor","9":"Farrux",
            "10":"Hazem","11":"Nadejda","12":"Nina","13":"Dilyara","14":"Veronika",
            "15":"Tyotya Kseniya","16":"Yulya","17":"Aleksandr","18":"Polina"
        },
        ru: {
            "1":"Хотинжон","2":"Зухриддин","3":"Оббос","4":"Қори ота",
            "5":"Отабек","6":"Аслбек","7":"Шерзод","8":"Сардор","9":"Фаррух",
            "10":"Хазем","11":"Надежда","12":"Нина","13":"Диляра","14":"Вероника",
            "15":"Тётя Ксения","16":"Юля","17":"Александр","18":"Полина"
        }
    };
    const gId = new URLSearchParams(window.location.search).get('id');
    const names = guestNames[lang] || guestNames['uz'];
    const gName = gId && names[gId] ? names[gId] : null;

    document.getElementById('welcome-title').textContent = gName ? `${L.guestPrefix} ${gName}!` : L.welcomeTitle;
    document.getElementById('welcome-sub').textContent = L.welcomeSub;
    document.getElementById('start-btn-text').textContent = L.startBtn;
    document.getElementById('hero-sub').textContent = L.heroSub;
    document.getElementById('card-title').textContent = gName ? `${L.guestPrefix} ${gName}!` : L.cardTitle;
    document.getElementById('card-text').textContent = L.cardText;
    document.getElementById('toy-title').textContent = L.toyTitle;
    document.getElementById('owners-label').textContent = L.ownersLabel;
    document.getElementById('owners-value').textContent = L.ownersValue;
    document.getElementById('when-label').textContent = L.whenLabel;
    document.getElementById('when-value').textContent = L.whenValue;
    document.getElementById('where-label').textContent = L.whereLabel;
    document.getElementById('map-btn').textContent = L.mapBtn;
    document.getElementById('timer-title').textContent = L.timerTitle;
    document.getElementById('l-kun').textContent = L.kun;
    document.getElementById('l-soat').textContent = L.soat;
    document.getElementById('l-daqiqa').textContent = L.daqiqa;
    document.getElementById('l-soniya').textContent = L.soniya;
    document.getElementById('footer-text').textContent = L.footerText;

    document.getElementById('calendar-month').textContent = L.calendarMonth;
    document.getElementById('calendar-caption').textContent = L.calendarCaption;
    L.weekdays.forEach((d, i) => { document.getElementById('cw-' + i).textContent = d; });
    const addCalBtn = document.getElementById('add-calendar-btn');
    if (!addCalBtn.classList.contains('added')) {
        document.getElementById('add-calendar-text').textContent = L.addCalendarBtn;
    }

    document.getElementById('schedule-title').textContent = L.scheduleTitle;
    L.schedule.forEach((item, i) => {
        document.getElementById('sch-time-' + (i + 1)).textContent = item.time;
        document.getElementById('sch-text-' + (i + 1)).textContent = item.text;
    });
}

// ── ADD TO CALENDAR (.ics) ──
function downloadICS() {
    const L = LANGS[currentLang];
    const pad = n => String(n).padStart(2, '0');
    const fmt = d => `${d.getUTCFullYear()}${pad(d.getUTCMonth()+1)}${pad(d.getUTCDate())}T${pad(d.getUTCHours())}${pad(d.getUTCMinutes())}00Z`;
    // Wedding: Aug 3 2026, 18:00–22:00 local (UTC+5, Tashkent) → 13:00–17:00 UTC
    const start = new Date('2026-08-03T13:00:00Z');
    const end   = new Date('2026-08-03T17:00:00Z');
    const ics = [
        'BEGIN:VCALENDAR', 'VERSION:2.0', 'PRODID:-//MZ Wedding//UZ', 'BEGIN:VEVENT',
        `UID:mz-wedding-2026@toy`,
        `DTSTAMP:${fmt(new Date())}`,
        `DTSTART:${fmt(start)}`,
        `DTEND:${fmt(end)}`,
        `SUMMARY:${L.icsTitle}`,
        `LOCATION:${L.icsLocation}`,
        'END:VEVENT', 'END:VCALENDAR'
    ].join('\r\n');

    const blob = new Blob([ics], { type: 'text/calendar;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'toy-mz-2026.ics';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    const btn = document.getElementById('add-calendar-btn');
    btn.classList.add('added');
    document.getElementById('add-calendar-text').textContent = L.addCalendarDone;
    setTimeout(() => {
        btn.classList.remove('added');
        document.getElementById('add-calendar-text').textContent = L.addCalendarBtn;
    }, 2400);
}

