// ── BUTTERFLIES ──
function burstButterflies(x, y) {
    for (let i = 0; i < 32; i++) {
        const b = document.createElement('div');
        b.className = 'butterfly';
        b.style.left = x + 'px';
        b.style.top = y + 'px';
        const dx = (Math.random() - 0.5) * 700;
        const dy = (Math.random() - 0.9) * 850;
        b.style.setProperty('--x', dx + 'px');
        b.style.setProperty('--y', dy + 'px');
        b.style.setProperty('--r', (Math.random() * 360) + 'deg');
        const s = 18 + Math.random() * 18;
        b.style.width = b.style.height = s + 'px';
        b.style.animationDuration = (2 + Math.random() * 1.5) + 's';
        document.body.appendChild(b);
        setTimeout(() => b.remove(), 3800);
    }
}

// ── SAKURA ──
function initSakura() {
    const canvas = document.getElementById('sakura-canvas');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const app = document.getElementById('app');
    function resize() {
        canvas.width = app.clientWidth;
        canvas.height = window.innerHeight;
    }
    resize();
    window.addEventListener('resize', resize);

    function mkPetal(type) {
        return {
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height - canvas.height,
            size: Math.random() * 5 + 5,
            sy: Math.random() * 1.2 + 0.7,
            sx: Math.random() * 1.6 - 0.8,
            angle: Math.random() * 360,
            spin: Math.random() * 1.8 - 0.9,
            wind: Math.random() * 0.025,
            type,
            petals: Math.floor(Math.random()*3)+6
        };
    }
    const sakura = Array.from({length:42}, () => mkPetal('s'));
    const daisy  = Array.from({length:28}, () => mkPetal('d'));

    function drawSakura(p) {
        ctx.save(); ctx.translate(p.x,p.y); ctx.rotate(p.angle*Math.PI/180);
        ctx.beginPath();
        ctx.moveTo(0,0);
        ctx.bezierCurveTo(p.size,-p.size,p.size*2,p.size,0,p.size);
        ctx.bezierCurveTo(-p.size*2,p.size,-p.size,-p.size,0,0);
        ctx.fillStyle='rgba(255,182,210,0.72)'; ctx.fill();
        ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(0,p.size*0.8);
        ctx.strokeStyle='rgba(220,100,150,0.3)'; ctx.lineWidth=0.5; ctx.stroke();
        ctx.restore();
    }
    function drawDaisy(p) {
        ctx.save(); ctx.translate(p.x,p.y); ctx.rotate(p.angle*Math.PI/180);
        const pl=p.size*1.8, pw=p.size*0.55, cr=p.size*0.55;
        for(let i=0;i<p.petals;i++){
            const a=(i/p.petals)*Math.PI*2;
            ctx.save(); ctx.rotate(a);
            ctx.beginPath(); ctx.ellipse(0,-(cr+pl/2),pw,pl/2,0,0,Math.PI*2);
            ctx.fillStyle='rgba(255,255,252,0.88)'; ctx.fill();
            ctx.restore();
        }
        const g=ctx.createRadialGradient(0,0,0,0,0,cr);
        g.addColorStop(0,'rgba(255,230,80,0.95)'); g.addColorStop(1,'rgba(200,130,10,0.6)');
        ctx.beginPath(); ctx.arc(0,0,cr,0,Math.PI*2); ctx.fillStyle=g; ctx.fill();
        ctx.restore();
    }
    function upd(p) {
        p.y+=p.sy; p.x+=Math.sin(p.y*p.wind)*1.1+p.sx*0.3; p.angle+=p.spin;
        if(p.y>canvas.height+20){p.y=-20;p.x=Math.random()*canvas.width;}
    }
    function loop(){
        ctx.clearRect(0,0,canvas.width,canvas.height);
        sakura.forEach(p=>{drawSakura(p);upd(p);});
        daisy.forEach(p=>{drawDaisy(p);upd(p);});
        requestAnimationFrame(loop);
    }
    loop();
}

// ── TIMER ──
const targetDate = new Date('August 3, 2026 18:00:00').getTime();
function tick(){
    const d = targetDate - Date.now();
    if(d<=0){['days','hours','minutes','seconds'].forEach(i=>document.getElementById(i).textContent='00');return;}
    document.getElementById('days').textContent    = String(Math.floor(d/86400000)).padStart(2,'0');
    document.getElementById('hours').textContent   = String(Math.floor(d%86400000/3600000)).padStart(2,'0');
    document.getElementById('minutes').textContent = String(Math.floor(d%3600000/60000)).padStart(2,'0');
    document.getElementById('seconds').textContent = String(Math.floor(d%60000/1000)).padStart(2,'0');
}
tick(); setInterval(tick,1000);

function tickWelcome(){
    const d = targetDate - Date.now();
    if(d<=0){['w-days','w-hours','w-minutes','w-seconds'].forEach(i=>{const el=document.getElementById(i);if(el)el.textContent='00';});return;}
    const wd=document.getElementById('w-days');
    const wh=document.getElementById('w-hours');
    const wm=document.getElementById('w-minutes');
    const ws=document.getElementById('w-seconds');
    if(wd) wd.textContent=String(Math.floor(d/86400000)).padStart(2,'0');
    if(wh) wh.textContent=String(Math.floor(d%86400000/3600000)).padStart(2,'0');
    if(wm) wm.textContent=String(Math.floor(d%3600000/60000)).padStart(2,'0');
    if(ws) ws.textContent=String(Math.floor(d%60000/1000)).padStart(2,'0');
}
tickWelcome(); setInterval(tickWelcome,1000);

