// ════════════════════════════════════════════
//  PNG RING ANIMATION
// ════════════════════════════════════════════
(function() {
const RING1_SRC = "data:image/png;base64,";
const RING2_SRC = "data:image/png;base64,";

// Preload images
const img1 = new Image(); img1.src = RING1_SRC;
const img2 = new Image(); img2.src = RING2_SRC;

// Welcome screen: two rings bobbing side by side
function initWelcomeRings() {
    const canvas = document.getElementById('welcome-ring-canvas');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const W = canvas.width, H = canvas.height;
    let t = 0;
    const size = 100;

    function draw() {
        ctx.clearRect(0, 0, W, H);
        const y1 = H/2 - size/2 + Math.sin(t * 0.04) * 5;
        const y2 = H/2 - size/2 + Math.sin(t * 0.04 + 1.2) * 5;
        // Drop shadows
        ctx.save();
        ctx.fillStyle = 'rgba(140,80,0,0.12)';
        ctx.beginPath(); ctx.ellipse(72,  H-14, 32, 7, 0, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.ellipse(188, H-14, 32, 7, 0, 0, Math.PI*2); ctx.fill();
        ctx.restore();
        // Ring 1 (left) — gold with diamonds
        if (img1.complete) {
            ctx.save();
            ctx.translate(72, y1);
            // gentle rock
            ctx.rotate(Math.sin(t*0.035)*0.04);
            ctx.drawImage(img1, -size/2, 0, size, size);
            ctx.restore();
        }
        // Ring 2 (right) — rose gold flat
        if (img2.complete) {
            ctx.save();
            ctx.translate(188, y2);
            ctx.rotate(Math.sin(t*0.035 + 1.0)*0.04);
            ctx.drawImage(img2, -size/2, 0, size, size);
            ctx.restore();
        }
        t++;
        requestAnimationFrame(draw);
    }
    Promise.all([
        new Promise(r => { img1.onload = r; if(img1.complete) r(); }),
        new Promise(r => { img2.onload = r; if(img2.complete) r(); })
    ]).then(draw);
}

// Main animation: rings drop, clash, butterflies, fade
function startPNGRingAnimation(bgAudio) {
    const canvas = document.getElementById('ring-canvas-overlay');
    if (!canvas) return;
    const appEl = document.getElementById('app') || document.getElementById('mobile-app');
    canvas.width  = appEl.clientWidth;
    canvas.height = window.innerHeight;
    canvas.style.display = 'block';
    const ctx = canvas.getContext('2d');
    const W = canvas.width, H = canvas.height;
    const CX = W / 2;

    const SIZE = Math.min(W * 0.38, 160); // ring display size

    // Ring states
    const L = { x: CX - SIZE*0.38, y: -SIZE,       // start above screen
                 tx: CX - SIZE*0.28, ty: H*0.18,    // target
                 vx:0, vy:0, angle:0, va:-0.004, alpha:0, scale:1 };
    const R_ = { x: CX + SIZE*0.38, y: -SIZE,
                  tx: CX + SIZE*0.28, ty: H*0.18,
                  vx:0, vy:0, angle:0, va:0.004, alpha:0, scale:1 };

    let phase = 'drop';   // drop → clash → rest → fadeout
    let clashed = false;
    let clashGlow = 0;
    let sparkles = [];
    let restT = 0;
    let globalAlpha = 1;
    const ringSound = document.getElementById('ringSound');

    function spawnSparkles(x, y) {
        for (let i = 0; i < 35; i++) {
            const a = Math.random()*Math.PI*2;
            const sp = 80 + Math.random()*260;
            sparkles.push({
                x, y, vx: Math.cos(a)*sp, vy: Math.sin(a)*sp - 60,
                life: 1, dec: 0.5+Math.random()*0.7,
                rad: 2+Math.random()*5,
                hue: 30+Math.random()*30
            });
        }
    }

    function drawRingImg(img, state) {
        ctx.save();
        ctx.globalAlpha = state.alpha * globalAlpha;
        ctx.translate(state.x, state.y);
        ctx.rotate(state.angle);
        ctx.scale(state.scale, state.scale);
        // shadow under ring
        ctx.save();
        ctx.shadowColor = 'rgba(100,60,0,0.35)';
        ctx.shadowBlur  = 22;
        ctx.shadowOffsetY = 14;
        ctx.drawImage(img, -SIZE/2, -SIZE/2, SIZE, SIZE);
        ctx.restore();
        ctx.restore();
    }

    function frame() {
        if (phase === 'done') return;
        ctx.clearRect(0, 0, W, H);

        // ── DROP ──
        if (phase === 'drop') {
            [['left', L, img1], ['right', R_, img2]].forEach(([side, s, img]) => {
                const dx = s.tx - s.x, dy = s.ty - s.y;
                s.vx += dx * 0.1; s.vy += dy * 0.1 + 0.9;
                s.vx *= 0.72; s.vy *= 0.72;
                s.x += s.vx; s.y += s.vy;
                s.angle += s.va;
                s.alpha = Math.min(1, s.alpha + 0.05);
            });
            if (Math.abs(L.y-L.ty)<5 && Math.abs(L.vy)<2.5 && Math.abs(R_.y-R_.ty)<5) {
                phase = 'clash';
            }
        }

        // ── CLASH ──
        if (phase === 'clash') {
            if (!clashed) {
                clashed = true;
                clashGlow = 1.8;
                spawnSparkles(CX, (L.y+R_.y)/2);
                if (ringSound) { ringSound.currentTime=0; ringSound.play().catch(()=>{}); }
                const rect = appEl.getBoundingClientRect();
                setTimeout(() => burstButterflies(rect.left+rect.width/2, rect.top+(L.y+R_.y)/2), 60);
            }
            // Rings move toward each other
            L.x  += (CX - SIZE*0.18 - L.x)  * 0.1;
            R_.x += (CX + SIZE*0.18 - R_.x) * 0.1;
            L.angle  *= 0.9; R_.angle *= 0.9;
            // gentle float
            L.y  += Math.sin(restT*8)*0.4;
            R_.y += Math.sin(restT*8+Math.PI)*0.4;
            restT += 0.016;
            if (restT > 2.6) phase = 'fadeout';
        }

        // ── FADEOUT ──
        if (phase === 'fadeout') {
            globalAlpha = Math.max(0, globalAlpha - 0.022);
            L.y -= 1.8; R_.y -= 1.8;
            L.scale  = Math.max(0.5, L.scale  - 0.008);
            R_.scale = Math.max(0.5, R_.scale - 0.008);
            if (globalAlpha <= 0) {
                phase = 'done';
                canvas.style.display = 'none';
                bgAudio.play().catch(()=>{});
                return;
            }
        }

        // ── DRAW ──
        drawRingImg(img1, L);
        drawRingImg(img2, R_);

        // Clash glow
        if (clashGlow > 0) {
            const gy = (L.y+R_.y)/2;
            const cg = ctx.createRadialGradient(CX,gy,0, CX,gy,90);
            cg.addColorStop(0, `rgba(255,235,100,${Math.min(1,clashGlow*0.7)})` );
            cg.addColorStop(1, 'rgba(255,200,50,0)');
            ctx.beginPath(); ctx.arc(CX,gy,90,0,Math.PI*2);
            ctx.fillStyle = cg; ctx.fill();
            clashGlow -= 0.04;
        }

        // Sparkles
        sparkles = sparkles.filter(s=>s.life>0);
        sparkles.forEach(s=>{
            s.x+=s.vx*0.016; s.y+=s.vy*0.016; s.vy+=220*0.016; s.life-=s.dec*0.016*3;
            ctx.save(); ctx.globalAlpha=Math.max(0,s.life)*globalAlpha;
            const sg=ctx.createRadialGradient(s.x,s.y,0,s.x,s.y,s.rad);
            sg.addColorStop(0,`hsl(${s.hue},90%,70%)`); sg.addColorStop(1,`hsla(${s.hue},80%,55%,0)`);
            ctx.beginPath(); ctx.arc(s.x,s.y,s.rad,0,Math.PI*2); ctx.fillStyle=sg; ctx.fill();
            ctx.restore();
        });

        requestAnimationFrame(frame);
    }

    Promise.all([
        new Promise(r=>{img1.onload=r;if(img1.complete)r();}),
        new Promise(r=>{img2.onload=r;if(img2.complete)r();})
    ]).then(()=>requestAnimationFrame(frame));
}

// init welcome rings on load
document.addEventListener('DOMContentLoaded', initWelcomeRings);

// expose to global
window.startPNGRingAnimation = startPNGRingAnimation;
})();
